## 2. **Update UserRepository/DAO**
__Add `communicationPreferences` to database insert and query operations__

```kotlin
// /src/main/kotlin/com/example/app/repositories/UserRepository.kt
interface UserRepository {
    suspend fun create(
        username: String,
        email: String,
        communicationPreferences: UserCommunicationPreferences
    ): User

    suspend fun updateCommunicationPreferences(
        userId: Long,
        communicationPreferences: UserCommunicationPreferences
    ): User

    suspend fun findByPreference(
        preference: UserCommunicationPreferences
    ): List<User>
}

// Implementation
@Singleton
class UserRepositoryImpl(private val dsl: DSLContext) : UserRepository {
    override suspend fun create(
        username: String,
        email: String,
        communicationPreferences: UserCommunicationPreferences
    ): User = withContext(Dispatchers.IO) {
        dsl.insertInto(USERS)
            .set(USERS.USERNAME, username)
            .set(USERS.EMAIL, email)
            .set(USERS.COMMUNICATION_PREFERENCES, communicationPreferences.name)
            .returning()
            .fetchOne()
            ?.toUser() ?: throw IllegalStateException("Failed to create user")
    }
}
```

