## 4. **Add Integration Tests**
__Test the complete flow of creating and updating communication preferences__

```kotlin
// /src/test/kotlin/com/example/app/controllers/UserControllerTest.kt
@MicronautTest
class UserControllerTest {

    @Inject
    lateinit var client: HttpClient

    @Test
    fun `should create user with communication preferences`() = runBlocking {
        val request = CreateUserRequest(
            username = "testuser",
            email = "test@example.com",
            communicationPreferences = UserCommunicationPreferences.SMS
        )

        val response = client.toBlocking().exchange(
            HttpRequest.POST("/users", request),
            User::class.java
        )

        assertEquals(HttpStatus.OK, response.status)
        assertEquals(UserCommunicationPreferences.SMS, response.body()?.communicationPreferences)
    }

    @Test
    fun `should reject user creation with null communication preferences`() = runBlocking {
        val request = CreateUserRequest(
            username = "testuser",
            email = "test@example.com",
            communicationPreferences = null
        )

        val exception = assertThrows<HttpClientResponseException> {
            client.toBlocking().exchange(
                HttpRequest.POST("/users", request),
                User::class.java
            )
        }

        assertEquals(HttpStatus.BAD_REQUEST, exception.status)
    }

    @Test
    fun `should update user communication preferences`() = runBlocking {
        // Create user first
        val user = createTestUser(UserCommunicationPreferences.EMAIL)

        // Update preferences
        val updateRequest = UpdateCommunicationPreferencesRequest(
            communicationPreferences = UserCommunicationPreferences.PUSH
        )

        val response = client.toBlocking().exchange(
            HttpRequest.PATCH("/users/${user.id}/communication-preferences", updateRequest),
            User::class.java
        )

        assertEquals(HttpStatus.OK, response.status)
        assertEquals(UserCommunicationPreferences.PUSH, response.body()?.communicationPreferences)
    }
}
```

