## 5. **Update OpenAPI/Swagger Documentation**
__Document the new field and endpoints in API specification__

```kotlin
// /src/main/kotlin/com/example/app/controllers/UserController.kt
import io.swagger.v3.oas.annotations.*
import io.swagger.v3.oas.annotations.media.*
import io.swagger.v3.oas.annotations.responses.*

@Operation(
    summary = "Create a new user",
    description = "Creates a new user with specified communication preferences"
)
@ApiResponses(
    value = [
        ApiResponse(
            responseCode = "200",
            description = "User created successfully",
            content = [Content(schema = Schema(implementation = User::class))]
        ),
        ApiResponse(
            responseCode = "400",
            description = "Invalid input - communication preferences required"
        )
    ]
)
@POST(
    "/users",
    consumes = [MediaType.APPLICATION_JSON],
    produces = [MediaType.APPLICATION_JSON]
)
suspend fun createUser(
    @RequestBody 
    @Schema(description = "User creation request with communication preferences")
    newUser: CreateUserRequest
): User {
    validateCommunicationPreferences(newUser.communicationPreferences)
    val communicationPreferences = newUser.communicationPreferences!!
    logger.info("Creating user with communication preferences: $communicationPreferences")
    return userRepository.create(
        newUser.username, 
        newUser.email, 
        communicationPreferences
    )
}
```

